// ══════════════════════════════════════════════
// SAFETY LAYER — replaces broken Guardrails node
// Detects prompt injection & sensitive data
// ══════════════════════════════════════════════

const input = $input.first().json;
const chatInput = String(input.chatInput || input.message || input.text || '');

const INJECTION_PATTERNS = [
  /ignore (previous|all|your) instructions/i,
  /delete all (tickets|data|logs|records)/i,
  /forget (everything|your instructions)/i,
  /you are now (a different|an unrestricted|DAN)/i,
  /act as (a different|an unrestricted)/i,
  /bypass (safety|restrictions|guardrails)/i,
  /reveal (your )?(system prompt|instructions)/i,
  /pretend (you are|to be) (an? )?(unrestricted|jailbroken)/i,
  /ignore previous/i,
  /disregard (your|all) instructions/i
];

const SENSITIVE_PATTERNS = [
  { pattern: /password\s*[:=]\s*\S+/i,    replacement: 'password=[REDACTED]' },
  { pattern: /api[_-]?key\s*[:=]\s*\S+/i, replacement: 'api_key=[REDACTED]' },
  { pattern: /secret\s*[:=]\s*\S+/i,      replacement: 'secret=[REDACTED]' },
  { pattern: /token\s*[:=]\s*\S+/i,       replacement: 'token=[REDACTED]' }
];

let blocked = false;
let blockReason = '';
for (const pattern of INJECTION_PATTERNS) {
  if (pattern.test(chatInput)) {
    blocked = true;
    blockReason = 'Prompt injection detected: ' + pattern.toString();
    break;
  }
}

let safeInput = chatInput;
const redactions = [];
if (!blocked) {
  for (const sp of SENSITIVE_PATTERNS) {
    if (sp.pattern.test(safeInput)) {
      redactions.push('Redacted: ' + sp.replacement.split('=')[0]);
      safeInput = safeInput.replace(sp.pattern, sp.replacement);
    }
  }
}

return [{
  json: {
    chatInput: safeInput,
    originalInput: chatInput,
    blocked,
    blockReason,
    redactions,
    safetyChecked: true,
    timestamp: new Date().toISOString(),
    sessionId: Math.random().toString(36).slice(2, 11) 
  }
}];

// Returns a safe refusal message back into the chat flow
const reason = $input.first().json.blockReason || 'Unknown';
return [{
  json: {
    output: 'This request is outside my role and has been blocked. Prompt injection attempts are logged. How can I help you with an IT incident today?',
    blocked: true,
    blockReason: reason
  }
}];

const service = $fromAI('service', 'Service name (nginx, vpn, app, mail, disk)', 'string');
const level = $fromAI('level', 'Log level filter (ERROR, WARN, INFO, all)', 'string', 'all');
const since = $fromAI('since', 'Time range (1h, 6h, 24h)', 'string', '1h');

const logDatabase = {
  app: [
    { timestamp: '2026-03-04T10:45:23Z', level: 'ERROR', message: 'OOMKilled: container exceeded 2Gi memory limit' },
    { timestamp: '2026-03-04T10:45:20Z', level: 'ERROR', message: 'OutOfMemoryError: Java heap space' },
    { timestamp: '2026-03-04T10:45:15Z', level: 'WARN',  message: 'Memory usage at 96%, GC overhead limit exceeded' },
    { timestamp: '2026-03-04T10:45:10Z', level: 'INFO',  message: 'Service restarting... (attempt 7 of 10)' },
    { timestamp: '2026-03-04T10:44:58Z', level: 'ERROR', message: 'NullPointerException at OrderService.java:142' },
    { timestamp: '2026-03-04T10:44:45Z', level: 'ERROR', message: 'Application crash detected - core dumped' }
  ],
  nginx: [
    { timestamp: '2026-03-04T10:45:23Z', level: 'ERROR', message: 'upstream timed out (110) reading response header from 10.0.1.10:8080' },
    { timestamp: '2026-03-04T10:45:20Z', level: 'ERROR', message: '502 Bad Gateway for POST /api/orders' },
    { timestamp: '2026-03-04T10:45:15Z', level: 'WARN',  message: 'worker connections running out (1024/1024 used)' },
    { timestamp: '2026-03-04T10:44:50Z', level: 'ERROR', message: 'Upstream server connection refused: 10.0.1.10:8080' }
  ],
  vpn: [
    { timestamp: '2026-03-04T10:45:23Z', level: 'ERROR', message: 'TLS handshake failed for peer 203.0.113.42' },
    { timestamp: '2026-03-04T10:45:20Z', level: 'ERROR', message: 'Certificate expired: CN=vpn.internal, expiry=2026-03-01' },
    { timestamp: '2026-03-04T10:45:15Z', level: 'WARN',  message: 'Certificate expiring in 0 days — renew immediately' },
    { timestamp: '2026-03-04T10:45:10Z', level: 'WARN',  message: 'High latency detected: 250ms on tunnel' },
    { timestamp: '2026-03-04T10:44:45Z', level: 'ERROR', message: 'Authentication failed for user admin@company.com' }
  ],
  mail: [
    { timestamp: '2026-03-04T10:45:23Z', level: 'ERROR', message: 'SMTP connection timeout to relay.example.com:587' },
    { timestamp: '2026-03-04T10:45:20Z', level: 'WARN',  message: 'Mail queue size approaching limit: 950/1000' },
    { timestamp: '2026-03-04T10:45:15Z', level: 'ERROR', message: 'Mailbox quota exceeded for john@company.com (2048MB/2048MB)' },
    { timestamp: '2026-03-04T10:44:50Z', level: 'ERROR', message: 'IMAP authentication failed for john@company.com' }
  ],
  disk: [
    { timestamp: '2026-03-04T10:45:23Z', level: 'ERROR', message: 'Write failed: No space left on /dev/sda1' },
    { timestamp: '2026-03-04T10:45:20Z', level: 'ERROR', message: '/var/log/app.log grew by 4.2GB in last hour' },
    { timestamp: '2026-03-04T10:45:10Z', level: 'WARN',  message: '/dev/sda1 usage at 91% — critical threshold exceeded' },
    { timestamp: '2026-03-04T10:44:30Z', level: 'WARN',  message: 'I/O error on device /dev/sdb — check SMART status' }
  ]
};

const svc = String(service).toLowerCase();
let logs = logDatabase[svc] || [{ timestamp: new Date().toISOString(), level: 'INFO', message: 'No logs found for service: ' + svc }];

if (level && level.toLowerCase() !== 'all') {
  logs = logs.filter(l => l.level.toLowerCase() === level.toLowerCase());
}

return JSON.stringify({
  service: svc, level, since,
  logCount: logs.length,
  logs: logs.map(l => `[${l.timestamp}] [${l.level}] ${l.message}`).join('\n'),
  summary: {
    errorCount: logs.filter(l => l.level === 'ERROR').length,
    warnCount: logs.filter(l => l.level === 'WARN').length,
    infoCount: logs.filter(l => l.level === 'INFO').length
  }
});

const server = $fromAI('server', 'Server name (web-01, db-01, vpn-01, mail-01, app-01)', 'string');

const metricsDatabase = {
  'app-01':  { cpu: 95, memory: 99, disk: 62, uptime: '0d 12m', load: '12.1 11.3 9.8', status: 'critical' },
  'web-01':  { cpu: 87, memory: 72, disk: 91, uptime: '14d 3h', load: '8.2 7.9 7.1',   status: 'degraded' },
  'db-01':   { cpu: 34, memory: 81, disk: 80, uptime: '120d 3h',load: '4.5 4.2 4.0',   status: 'healthy' },
  'vpn-01':  { cpu: 23, memory: 70, disk: 45, uptime: '89d 15h', load: '0.5 0.4 0.3',  status: 'down' },
  'mail-01': { cpu: 56, memory: 85, disk: 76, uptime: '67d 8h',  load: '2.0 1.9 1.7',  status: 'degraded' }
};

const key = String(server).toLowerCase();
const data = metricsDatabase[key] || { cpu: 55, memory: 60, disk: 55, uptime: '5d', load: '2.0 1.9 1.8', status: 'unknown' };

const alerts = [];
if (data.cpu > 80)    alerts.push('CRITICAL: CPU at ' + data.cpu + '% (threshold 80%)');
if (data.memory > 85) alerts.push('CRITICAL: Memory at ' + data.memory + '% (threshold 85%)');
if (data.disk > 90)   alerts.push('CRITICAL: Disk at ' + data.disk + '% (threshold 90%)');

return JSON.stringify({
  server: key, timestamp: new Date().toISOString(),
  healthStatus: data.status, alerts,
  metrics: {
    cpu_pct: data.cpu, memory_pct: data.memory,
    disk_pct: data.disk, uptime: data.uptime, load_avg: data.load
  },
  summary: `CPU:${data.cpu}% MEM:${data.memory}% DISK:${data.disk}% UP:${data.uptime}`
});

const service = $fromAI('service', 'Service name (nginx, vpn, app, mail, database)', 'string');
const server = $fromAI('server', 'Server name (optional)', 'string', 'auto');

const db = {
  'app-01':  { app:      { status: 'restarting', state: 'unstable', uptime: '3 minutes',  restarts_24h: 12, lastRestart: '2 minutes ago',  pid: 8472,  port: 8080, healthCheck: 'failing' }},
  'web-01':  { nginx:    { status: 'degraded',   state: 'running',  uptime: '14d 3h',      restarts_24h: 3,  lastRestart: '4 hours ago',   pid: 5678,  port: 80,   healthCheck: 'warning' }},
  'db-01':   { database: { status: 'healthy',    state: 'running',  uptime: '120d 3h',     restarts_24h: 0,  lastRestart: '120 days ago',  pid: 9012,  port: 5432, healthCheck: 'passing' }},
  'vpn-01':  { vpn:      { status: 'down',        state: 'stopped',  uptime: '0d 0h',       restarts_24h: 12, lastRestart: '18 min ago',    pid: null,  port: 1194, healthCheck: 'failing' }},
  'mail-01': { mail:     { status: 'degraded',   state: 'running',  uptime: '2 hours',     restarts_24h: 3,  lastRestart: '15 min ago',    pid: 7890,  port: 25,   healthCheck: 'warning' }}
};

const svc = String(service).toLowerCase();
const srv = String(server).toLowerCase();

let result = null;
let foundServer = null;

if (srv !== 'auto' && db[srv] && db[srv][svc]) {
  result = db[srv][svc];
  foundServer = srv;
} else {
  for (const [s, services] of Object.entries(db)) {
    if (services[svc]) { result = services[svc]; foundServer = s; break; }
  }
}

if (!result) result = { status: 'unknown', state: 'unknown', uptime: 'N/A', restarts_24h: 0, lastRestart: 'N/A', pid: null, port: null, healthCheck: 'unknown' };

const crashLoop = result.restarts_24h > 5;
const warning = crashLoop ? 'CRASH LOOP DETECTED: ' + result.restarts_24h + ' restarts in 24h — treat as critical' : null;

return JSON.stringify({
  server: foundServer || 'unknown', service: svc,
  timestamp: new Date().toISOString(),
  status: result.status, state: result.state,
  uptime: result.uptime, restarts_24h: result.restarts_24h,
  lastRestart: result.lastRestart,
  processInfo: { pid: result.pid, port: result.port },
  healthCheck: result.healthCheck,
  crash_loop_detected: crashLoop,
  warning,
  summary: `${svc} on ${foundServer}: ${result.status} (${result.restarts_24h} restarts/24h, health: ${result.healthCheck})`
});

const title       = $fromAI('title', 'Short incident title', 'string');
const severity    = $fromAI('severity', 'Severity: low|medium|high|critical', 'string', 'medium');
const description = $fromAI('description', 'Full diagnostic summary with evidence', 'string');
const team        = $fromAI('assigned_team', 'Team: IT Operations|Network Team|SRE Team|Mail Admin', 'string', 'IT Operations');

const ticketId = 'INC-' + Math.floor(1000 + Math.random() * 9000);
const slaMap = { critical: '1 hour', high: '4 hours', medium: '24 hours', low: '72 hours' };

return JSON.stringify({
  ticket_id:     ticketId,
  status:        'open',
  title,
  severity,
  description,
  assigned_team: team,
  created_at:    new Date().toISOString(),
  sla_target:    slaMap[severity] || '24 hours',
  created_by:    'Otic IT Support Agent'
});

// ══════════════════════════════════════════
// OBSERVABILITY TRACE LOGGER
// Formats agent execution as a visible trace
// ══════════════════════════════════════════

const items = $input.all();
const traces = [];

for (const item of items) {
  const json = item.json || {};
  const meta = json.metadata || {};
  const subNode = meta.subNodeExecutionData || {};
  const prevRequests = subNode.metadata?.previousRequests || [];
  const actions = subNode.actions || [];

  const steps = [];

  // Capture tool calls from previous requests
  prevRequests.forEach((req, i) => {
    const action = req.action || {};
    steps.push({
      step: i + 1,
      phase: 'ACTION → OBSERVATION',
      tool: action.tool || action.nodeName || 'unknown',
      input: JSON.stringify(action.toolInput || action.input || {}),
      output: Array.isArray(req.observation)
        ? req.observation.map(o => o.text || JSON.stringify(o)).join(' ')
        : String(req.observation || ''),
      log: action.log || action.messageLog || ''
    });
  });

  // Also pick up live actions
  actions.forEach((a, i) => {
    if (a.action?.type === 'ai_tool') {
      steps.push({
        step: prevRequests.length + i + 1,
        phase: 'ACTION',
        tool: a.action.nodeName,
        input: JSON.stringify(a.action.input || {}),
        output: 'Executing...',
        log: ''
      });
    }
  });

  const formatted = steps.map(s =>
    `━━━ STEP ${s.step}: ${s.phase} ━━━\n` +
    `  Tool    : ${s.tool}\n` +
    `  Input   : ${s.input}\n` +
    `  Output  : ${s.output.slice(0, 300)}${s.output.length > 300 ? '...' : ''}\n` +
    `  Thought : ${s.log.slice(0, 200)}${s.log.length > 200 ? '...' : ''}`
  ).join('\n\n');

  traces.push({
    executionId: $execution?.id || 'unknown',
    timestamp: new Date().toISOString(),
    totalSteps: steps.length,
    steps,
    formattedTrace: formatted || 'No tool calls recorded in this execution.',
    finalOutput: json.output || json
  });
}

return [{ json: { traces, traceCount: traces.length, generatedAt: new Date().toISOString() } }];

// Format Ticket Data — passes extracted fields to Trello
// Fields are already structured by Extract Ticket Fields node
const item = $input.first().json;
return [{
  json: {
    ticket_title:        item.ticket_title        || item.incident_summary || 'IT Incident',
    ticket_description:  item.ticket_description  || 'No description',
    severity:            item.severity             || 'medium',
    assigned_team:       item.assigned_team        || 'IT Operations',
    incident_summary:    item.incident_summary     || 'IT Incident',
    root_cause:          item.root_cause           || '',
    recommended_actions: item.recommended_actions  || '',
    evidence_summary:    item.evidence_summary     || ''
  }
}];

// ── Extract Ticket Fields ────────────────────────────────────────────
// Reads the agent's natural language output and extracts structured
// fields for Trello. Replaces the broken outputParserStructured node.

const items = $input.all();
const results = [];

for (const item of items) {
  const raw = String(
    item.json.output ||
    item.json.text ||
    item.json.response ||
    item.json.message ||
    JSON.stringify(item.json)
  );

  // ── Helper: extract line after a label emoji ─────────────────────
  const extract = (pattern) => {
    const m = raw.match(pattern);
    return m ? m[1].trim() : null;
  };

  // ── Extract each field from the formatted agent output ───────────
  const incident_summary = extract(/🔍 INCIDENT:\s*(.+)/i)
    || extract(/INCIDENT[:\s]+(.+)/i)
    || 'IT Incident';

  // Severity: look for emoji label first, then fallback keyword scan
  let severity = extract(/🎯 SEVERITY:\s*(critical|high|medium|low)/i)
    || extract(/SEVERITY[:\s]+(critical|high|medium|low)/i);
  if (!severity) {
    if (/critical/i.test(raw))     severity = 'critical';
    else if (/\bhigh\b/i.test(raw)) severity = 'high';
    else if (/medium/i.test(raw))   severity = 'medium';
    else                            severity = 'low';
  }

  // Team assignment
  let assigned_team = extract(/👥 TEAM:\s*(.+)/i)
    || extract(/TEAM[:\s]+(IT Operations|Network Team|SRE Team|Mail Admin)/i);
  if (!assigned_team) {
    if (/network team/i.test(raw))      assigned_team = 'Network Team';
    else if (/sre team/i.test(raw))     assigned_team = 'SRE Team';
    else if (/mail admin/i.test(raw))   assigned_team = 'Mail Admin';
    else                                assigned_team = 'IT Operations';
  }

  // Root cause: text after ⚠️ ROOT CAUSE: up to next section
  const root_cause = extract(/⚠️ ROOT CAUSE:\s*(.+?)(?=\n[✅👥🎯🎫]|\n━|$)/s)
    || extract(/ROOT CAUSE[:\s]+(.+?)(?=\n[A-Z✅]|$)/s)
    || 'Under investigation';

  // Recommended actions: numbered list after ✅ ACTIONS:
  const actionsMatch = raw.match(/✅ ACTIONS:\s*([\s\S]+?)(?=\n👥|\n🎯|\n🎫|\n━|$)/i);
  const recommended_actions = actionsMatch
    ? actionsMatch[1].trim()
    : extract(/ACTIONS[:\s]+([\s\S]+?)(?=\n[A-Z👥🎯]|$)/i) || 'See agent response';

  // Evidence: bullet list after 📋 EVIDENCE:
  const evidenceMatch = raw.match(/📋 EVIDENCE:\s*([\s\S]+?)(?=\n📖|\n⚠️|\n✅|$)/i);
  const evidence_summary = evidenceMatch
    ? evidenceMatch[1].trim()
    : 'See agent response for full evidence';

  // Runbook reference
  const runbook = extract(/📖 RUNBOOK:\s*([\s\S]+?)(?=\n⚠️|\n✅|$)/i) || '';

  const severityLabels = {
    critical: '🔴 CRITICAL',
    high:     '🟠 HIGH',
    medium:   '🟡 MEDIUM',
    low:      '🟢 LOW'
  };

  results.push({
    json: {
      // Fields for Trello
      ticket_title:        incident_summary,
      ticket_description:
        `🔍 INCIDENT ANALYSIS\n\n` +
        `⚠️ ROOT CAUSE:\n${root_cause}\n\n` +
        `📋 EVIDENCE:\n${evidence_summary}\n\n` +
        `📖 RUNBOOK REFERENCE:\n${runbook}\n\n` +
        `✅ RECOMMENDED ACTIONS:\n${recommended_actions}\n\n` +
        `👥 Team: ${assigned_team} | ${severityLabels[severity] || severity.toUpperCase()}\n` +
        `🤖 Auto-generated by Otic IT Support Agent`,
      severity,
      assigned_team,
      incident_summary,
      root_cause,
      recommended_actions,
      evidence_summary,
      // Pass through raw output for observability
      raw_agent_output: raw
    }
  });
}

return results;
